class Solution {
    public String strWithout3a3b(int a, int b) {
        StringBuilder sb = new StringBuilder();
        while (a > 0 || b > 0) {
            if (a >= b && b > 0) {
                sb.append("b");
                b--;
            } else if (a > b && a > 0) {
                sb.append("a");
                a--;
            } else if (b > a && a > 0) {
                sb.append("a");
                a--;
            } else {
                sb.append("b");
                b--;
            }
        }
        return sb.toString();
    }
}
```
